#include <iostream>
#include <string>

class GameStats {
private:
    static int totalEnemiesKilled;
    static int totalPlayers;
    static int currentPlayers;
    static int highScore;

public:
    // Static methods
    static void enemyKilled() {
        totalEnemiesKilled++;
        std::cout << "Enemy killed! Total: " << totalEnemiesKilled << std::endl;
    }

    static void playerJoined() {
        totalPlayers++;
        currentPlayers++;
        std::cout << "Player joined! Total: " << totalPlayers 
                  << ", Current: " << currentPlayers << std::endl;
    }

    static void playerLeft() {
        currentPlayers--;
        std::cout << "Player left! Current: " << currentPlayers << std::endl;
    }

    static void updateHighScore(int score) {
        if (score > highScore) {
            highScore = score;
            std::cout << "New high score: " << highScore << "!" << std::endl;
        }
    }

    static void displayStats() {
        std::cout << "\n=== Game Statistics ===" << std::endl;
        std::cout << "Total Enemies Killed: " << totalEnemiesKilled << std::endl;
        std::cout << "Total Players: " << totalPlayers << std::endl;
        std::cout << "Current Players: " << currentPlayers << std::endl;
        std::cout << "High Score: " << highScore << std::endl;
    }
};

// Initialize static members
int GameStats::totalEnemiesKilled = 0;
int GameStats::totalPlayers = 0;
int GameStats::currentPlayers = 0;
int GameStats::highScore = 0;

// Class with static members for instance tracking
class Player {
private:
    std::string name;
    int score;
    static int playerCount;

public:
    Player(std::string n) : name(n), score(0) {
        playerCount++;
        GameStats::playerJoined();
        std::cout << "Player " << name << " created (" << playerCount << " total)" << std::endl;
    }

    ~Player() {
        playerCount--;
        GameStats::playerLeft();
        std::cout << "Player " << name << " destroyed" << std::endl;
    }

    void killEnemy() {
        score += 10;
        GameStats::enemyKilled();
        GameStats::updateHighScore(score);
        std::cout << name << " scored: " << score << std::endl;
    }

    void display() const {
        std::cout << "Player: " << name << ", Score: " << score << std::endl;
    }

    static int getPlayerCount() {
        return playerCount;
    }
};

int Player::playerCount = 0;

int main() {
    std::cout << "=== Static Members ===" << std::endl;

    // Access static methods without creating objects
    std::cout << "\nInitial stats:" << std::endl;
    GameStats::displayStats();

    std::cout << "\n=== Creating Players ===" << std::endl;
    Player hero("Aragorn");
    Player wizard("Gandalf");

    std::cout << "\n=== Combat ===" << std::endl;
    hero.killEnemy();
    hero.killEnemy();
    wizard.killEnemy();

    std::cout << "\n=== Player Count ===" << std::endl;
    std::cout << "Active players: " << Player::getPlayerCount() << std::endl;

    std::cout << "\n=== Final Stats ===" << std::endl;
    GameStats::displayStats();

    std::cout << "\n=== End of main ===" << std::endl;
    // Destructors called automatically

    return 0;
}

phase2.brokenCode:
#include <iostream>

class Counter {
private:
    static int count;
    // Forgot to define static member outside class!
};

int main() {
    // ERROR: undefined reference
    std::cout << Counter::count << std::endl;
    return 0;
}

phase2.explanation:
You declared a static member but never defined it!

**The fix:**
```cpp
class Counter {
private:
    static int count;
};

int Counter::count = 0;  // ← Define it!
```

**Why this happens:**
- Declaration: `static int count;` — says it exists
- Definition: `int Counter::count = 0;` — gives it memory
- You need both!

**PlusPlus-chan says:**
"Static members are declared in the class and defined outside. Always define them. The linker will complain if you don't."

