#include <iostream>
#include <string>

class GameSession {
private:
    static int totalSessions;
    static int totalEnemiesDefeated;
    static int globalHighScore;

    std::string playerName;
    int score;

public:
    GameSession(std::string name) : playerName(name), score(0) {
        totalSessions++;
        std::cout << "Session started for " << playerName << std::endl;
    }

    ~GameSession() {
        std::cout << "Session ended for " << playerName << std::endl;
    }

    void addScore(int points) {
        score += points;
        totalEnemiesDefeated++;
        if (score > globalHighScore) {
            globalHighScore = score;
        }
        std::cout << playerName << " scored " << score << " points!" << std::endl;
    }

    static void displayGlobalStats() {
        std::cout << "\n=== Global Stats ===" << std::endl;
        std::cout << "Total Sessions: " << totalSessions << std::endl;
        std::cout << "Total Enemies Defeated: " << totalEnemiesDefeated << std::endl;
        std::cout << "Global High Score: " << globalHighScore << std::endl;
    }

    static int getTotalSessions() {
        return totalSessions;
    }
};

// Static member definitions
int GameSession::totalSessions = 0;
int GameSession::totalEnemiesDefeated = 0;
int GameSession::globalHighScore = 0;

int main() {
    GameSession player1("Aragorn");
    GameSession player2("Legolas");

    player1.addScore(50);
    player2.addScore(75);
    player1.addScore(30);

    GameSession::displayGlobalStats();

    return 0;
}
